/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const n = nums.length;
    if (n === 0) {
        return 0;
    }

    // DP state:
    // dp[i][0]: Maximum score of an alternating subsequence ending at index i,
    //            where the sequence ends with an element nums[i] that is GREATER than the previous element. (Up move)
    // dp[i][1]: Maximum score of an alternating subsequence ending at index i,
    //            where the sequence ends with an element nums[i] that is SMALLER than the previous element. (Down move)

    // Initialize DP table with zeros. Size n x 2.
    const dp = Array(n).fill(0).map(() => [0, 0]);

    let maxScore = 0;

    for (let i = 0; i < n; i++) {
        // Base case: A subsequence of length 1 always has a score of nums[i].
        // It can be considered either starting up or starting down, but for initialization, we set it to nums[i].
        dp[i][0] = nums[i]; // Can end with an increase (or start)
        dp[i][1] = nums[i]; // Can end with a decrease (or start)

        for (let j = 0; j < i; j++) {
            // Check the distance constraint: i - j >= k
            if (i - j >= k) {
                // Case 1: Current element nums[i] is greater than the previous element nums[j]. (Up move: ... < nums[j] < nums[i])
                // This transition must come from a sequence ending at j where the last move was a DOWN move (dp[j][1]), 
                // OR it's the start of a sequence (already covered by initialization, but we ensure the best previous state is used).
                if (nums[i] > nums[j]) {
                    // New score = dp[j][1] (ending down at j) + nums[i]
                    // We take the max between current dp[i][0] and the new possibility.
                    dp[i][0] = Math.max(dp[i][0], dp[j][1] + nums[i]);
                }

                // Case 2: Current element nums[i] is smaller than the previous element nums[j]. (Down move: ... > nums[j] > nums[i])
                // This transition must come from a sequence ending at j where the last move was an UP move (dp[j][0]).
                if (nums[i] < nums[j]) {
                    // New score = dp[j][0] (ending up at j) + nums[i]
                    // We take the max between current dp[i][1] and the new possibility.
                    dp[i][1] = Math.max(dp[i][1], dp[j][0] + nums[i]);
                }
            }
        }

        // Update overall maximum score found so far
        maxScore = Math.max(maxScore, dp[i][0], dp[i][1]);
    }

    return maxScore;
}

