object Solution {
  def nums(nums: Array[Long]): Long = {
    val n = nums.length
    if (n == 0) return 0

    // dp[i][0]: Max score ending at index i, where nums[i] > previous element (Up move)
    // dp[i][1]: Max score ending at index i, where nums[i] < previous element (Down move)
    // Using Long for scores to prevent overflow, although given constraints, standard Int might suffice for sums up to 10^5 * 10^5, but Long is safer.
    val dp = Array.ofDim[Long](n, 2)

    var maxScore: Long = 0

    for (i <- 0 until n) {
      // Base case: Subsequence of length 1
      dp(i, 0) = nums(i)
      dp(i, 1) = nums(i)

      for (j <- 0 until i) {
        // Check distance constraint
        if (i - j >= k) {

          // Case 1: nums[i] > nums[j] (Up move: ... < nums[j] < nums[i])
          if (nums(i) > nums(j)) {
            // Must come from a sequence ending at j with a Down move (dp[j][1])
            // Maximize current dp[i][0]
            dp(i, 0) = Math.max(dp(i, 0), dp(j, 1) + nums(i))
          }

          // Case 2: nums[i] < nums[j] (Down move: ... > nums[j] > nums[i])
          if (nums(i) < nums(j)) {
            // Must come from a sequence ending at j with an Up move (dp[j][0])
            // Maximize current dp[i][1]
            dp(i, 1) = Math.max(dp(i, 1), dp(j, 0) + nums(i))
          }
        }
      }

      // Update overall maximum score
      maxScore = Math.max(maxScore, dp(i, 0))
      maxScore = Math.max(maxScore, dp(i, 1))
    }

    maxScore
  }
}
