                // This transition must come from a sequence ending at j where the last move was an UP move (dp[j][0]).
                if (nums[i] < nums[j]) {
                    // New score = dp[j][0] (ending up at j) + nums[i]
                    // We take the max between current dp[i][1] and the new possibility.
                    dp[i][1] = Math.max(dp[i][1], dp[j][0] + nums[i]);
                }
            }
        }

        // Update overall maximum score found so far
        maxScore = Math.max(maxScore, dp[i][0], dp[i][1]);
    }

    return maxScore;
}
